.ctc-wrap { max-width: 1080px; margin: 0 auto; padding: 0 24px; }
.ctc-hero { text-align: center; padding: 64px 0 56px; }
.ctc-label { font-size: 11px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: #ff5757; margin-bottom: 14px; }
.ctc-hero h1 { font-size: clamp(32px, 4.5vw, 56px); font-weight: 700; color: #0f172a; line-height: 1.1; letter-spacing: -1.5px; margin-bottom: 16px; }
.ctc-hero h1 em { font-style: italic; color: #ff5757; }
.ctc-hero p { font-size: 18px; color: #64748b; max-width: 580px; margin: 0 auto 32px; line-height: 1.65; }
.ctc-hero-ctas { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.ctc-btn { display: inline-flex; align-items: center; gap: 8px; padding: 13px 24px; border-radius: 100px; font-size: 14px; font-weight: 600; text-decoration: none; transition: all .2s; }
.ctc-btn-primary { background: #ff5757; color: #fff; }
.ctc-btn-primary:hover { background: #0f172a; }
.ctc-btn-outline { background: transparent; color: #0f172a; border: 1.5px solid #e2e8f0; }
.ctc-btn-outline:hover { border-color: #0f172a; }

/* Scrolling tags */
.ctc-tags { overflow: hidden; margin-bottom: 64px; -webkit-mask: linear-gradient(90deg, transparent, black 10%, black 90%, transparent); mask: linear-gradient(90deg, transparent, black 10%, black 90%, transparent); }
.ctc-tags-track { display: flex; gap: 12px; animation: ctcScroll 30s linear infinite; width: max-content; }
@keyframes ctcScroll { from { transform: translateX(0); } to { transform: translateX(-50%); } }
.ctc-tag { padding: 8px 18px; background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 100px; font-size: 13px; font-weight: 600; color: #64748b; white-space: nowrap; }

/* Section */
.ctc-section { padding: 64px 0; border-top: 1px solid #f1f5f9; }
.ctc-section-label { font-size: 11px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: #94a3b8; margin-bottom: 12px; }
.ctc-section h2 { font-size: clamp(24px, 3vw, 36px); font-weight: 700; color: #0f172a; line-height: 1.2; letter-spacing: -0.5px; margin-bottom: 16px; }
.ctc-section p { font-size: 16px; color: #475569; line-height: 1.7; margin-bottom: 16px; max-width: 680px; }
.ctc-section p strong { color: #0f172a; }

/* Two-col layout */
.ctc-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 64px; align-items: start; }
.ctc-grid-3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; }

/* Cards */
.ctc-card { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 16px; padding: 24px; }
.ctc-card h3 { font-size: 15px; font-weight: 700; color: #0f172a; margin-bottom: 8px; }
.ctc-card p { font-size: 13px; color: #64748b; line-height: 1.6; margin: 0; }
.ctc-card-icon { width: 36px; height: 36px; border-radius: 8px; border: 1px solid #e2e8f0; background: #fff; display: flex; align-items: center; justify-content: center; margin-bottom: 14px; }

/* Source grid */
.ctc-sources { display: flex; flex-wrap: wrap; gap: 10px; margin: 24px 0; }
.ctc-source { display: inline-flex; align-items: center; gap: 8px; padding: 10px 16px; background: #fff; border: 1px solid #e2e8f0; border-radius: 10px; font-size: 13px; font-weight: 600; color: #0f172a; box-shadow: 0 1px 4px rgba(0,0,0,.04); }
.ctc-source-dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }
.ctc-source-badge { font-size: 10px; background: #fef3c7; color: #92400e; padding: 2px 7px; border-radius: 100px; font-weight: 700; margin-left: 4px; }

/* Dest grid */
.ctc-dests { display: flex; flex-wrap: wrap; gap: 10px; margin: 24px 0; }
.ctc-dest { display: inline-flex; align-items: center; gap: 8px; padding: 10px 16px; background: #fff; border: 1px solid #e2e8f0; border-radius: 10px; font-size: 13px; font-weight: 600; color: #0f172a; box-shadow: 0 1px 4px rgba(0,0,0,.04); }
.ctc-dest-syncific { border-style: dashed; color: #64748b; }
.ctc-dest-badge { font-size: 10px; background: #eff6ff; color: #2563eb; padding: 2px 7px; border-radius: 100px; font-weight: 700; }

/* Old vs new */
.ctc-compare { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin: 32px 0; }
.ctc-compare-col { border-radius: 14px; padding: 24px; }
.ctc-compare-col.old { background: #fef2f2; border: 1px solid #fecaca; }
.ctc-compare-col.new { background: #f0fdf4; border: 1px solid #bbf7d0; }
.ctc-compare-col h4 { font-size: 12px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px; margin-bottom: 16px; }
.ctc-compare-col.old h4 { color: #dc2626; }
.ctc-compare-col.new h4 { color: #16a34a; }
.ctc-compare-col ul { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 8px; }
.ctc-compare-col ul li { font-size: 13px; color: #475569; display: flex; align-items: flex-start; gap: 8px; line-height: 1.5; }
.ctc-compare-col.old ul li::before { content: '✗'; color: #dc2626; font-weight: 700; flex-shrink: 0; }
.ctc-compare-col.new ul li::before { content: '✓'; color: #16a34a; font-weight: 700; flex-shrink: 0; }

/* Stats */
.ctc-stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin: 40px 0; }
.ctc-stat { background: #fff; border: 1px solid #e2e8f0; border-radius: 14px; padding: 20px; text-align: center; }
.ctc-stat-num { font-size: 30px; font-weight: 800; background: linear-gradient(135deg, #ff5757, #2563eb); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; line-height: 1.2; }
.ctc-stat-label { font-size: 12px; color: #64748b; margin-top: 4px; }

/* CMS sections */
.ctc-cms { background: #f8fafc; border-radius: 20px; padding: 40px; margin-bottom: 24px; }
.ctc-cms h2 { font-size: 22px; font-weight: 700; color: #0f172a; margin-bottom: 12px; }
.ctc-cms p { font-size: 15px; color: #475569; line-height: 1.7; margin-bottom: 20px; }
.ctc-cms-bullets { display: flex; flex-direction: column; gap: 8px; }
.ctc-cms-bullet { display: flex; align-items: center; gap: 10px; font-size: 14px; color: #0f172a; font-weight: 500; }
.ctc-cms-bullet::before { content: ''; width: 4px; height: 4px; border-radius: 50%; background: #ff5757; flex-shrink: 0; }

/* Patent badge */
.ctc-patent { display: inline-flex; align-items: center; gap: 8px; font-size: 11px; font-weight: 600; color: #64748b; padding: 6px 14px; border: 1px solid #e2e8f0; border-radius: 100px; margin-bottom: 32px; }

/* CTA block */
.ctc-cta { background: #0f172a; border-radius: 20px; padding: 56px; text-align: center; margin-top: 80px; }
.ctc-cta h2 { font-size: 32px; font-weight: 700; color: #fff; margin-bottom: 12px; letter-spacing: -0.5px; }
.ctc-cta p { font-size: 16px; color: rgba(255,255,255,.6); max-width: 480px; margin: 0 auto 32px; line-height: 1.6; }
.ctc-btn-cta { background: #ff5757; color: #fff; }
.ctc-btn-cta:hover { background: #fff; color: #0f172a; }

@media (max-width: 800px) {
  .ctc-grid, .ctc-compare { grid-template-columns: 1fr; }
  .ctc-stats { grid-template-columns: repeat(2, 1fr); }
  .ctc-grid-3 { grid-template-columns: 1fr; }
}
@media (max-width: 480px) {
  .ctc-hero h1 { letter-spacing: -1px; }
  .ctc-hero-ctas { flex-direction: column; align-items: center; }
  .ctc-btn { width: 100%; justify-content: center; }
  .ctc-stats { grid-template-columns: repeat(2, 1fr); gap: 10px; }
  .ctc-stat-num { font-size: 24px; }
  .ctc-compare { gap: 12px; }
  .ctc-compare-col { padding: 18px; }
  .ctc-cms { padding: 24px; }
  .ctc-cta { padding: 36px 20px; }
  .ctc-cta h2 { font-size: 24px; }
  .ctc-sources, .ctc-dests { gap: 8px; }
  .ctc-source, .ctc-dest { font-size: 12px; padding: 8px 12px; }
  .ctc-tags-track { animation-duration: 20s; }
}

:root {
  --red:     #ff5757;
  --blue:    #2563eb;
  --gold:    #ffbd59;
  --dark:    #0a0a0a;
  --ink:     #0f172a;
  --muted:   #64748b;
  --border:  #e8ecf2;
  --card:    #ffffff;
  --light:   #f8fafc;
  --radius:  14px;
  --max:     1100px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }



.lf-nav {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  justify-content: center;
  padding: 32px 24px 0;
  max-width: var(--max);
  margin: 0 auto;
}
.lf-nav a {
  font-size: 13px;
  font-weight: 600;
  padding: 6px 16px;
  border-radius: 100px;
  border: 1px solid var(--border);
  color: var(--muted);
  text-decoration: none;
  transition: all .2s;
}
.lf-nav a:hover, .lf-nav a.active {
  background: var(--ink);
  color: #fff;
  border-color: var(--ink);
}


.lf-hero {
  text-align: center;
  padding: 64px 24px 56px;
  max-width: var(--max);
  margin: 0 auto;
}
.lf-hero-label {
  display: inline-block;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--red);
  margin-bottom: 16px;
}
.lf-hero h1 {

  font-size: clamp(36px, 5vw, 60px);
  font-weight: 400;
  line-height: 1.1;
  letter-spacing: -1.5px;
  color: var(--ink);
  margin-bottom: 20px;
}
.lf-hero h1 em {

  color: var(--red);
}
.lf-hero p {
  font-size: 18px;
  color: var(--muted);
  max-width: 580px;
  margin: 0 auto 32px;
  line-height: 1.65;
}
.lf-hero-ctas {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}
.lf-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: 100px;
  font-size: 14px;
  font-weight: 600;
  text-decoration: none;
  transition: all .2s;
  border: 1.5px solid transparent;
}
.lf-btn-primary {
  background: var(--red);
  color: #fff;
  border-color: var(--red);
}
.lf-btn-primary:hover { background: var(--ink); border-color: var(--ink); }
.lf-btn-outline {
  background: transparent;
  color: var(--ink);
  border-color: var(--border);
}
.lf-btn-outline:hover { border-color: var(--ink); }


.lf-section {
  max-width: var(--max);
  margin: 0 auto;
  padding: 0 24px 80px;
}

.lf-section-label {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 12px;
}
.lf-section-label span {
  display: inline-block;
  width: 24px;
  height: 1.5px;
  background: var(--border);
}

.lf-section-title {

  font-weight: 800;
  line-height: 1.15;
  letter-spacing: -0.8px;
  color: var(--ink);
  margin-bottom: 8px;
}
.lf-section-title em {  color: var(--red);

     font-weight: 400;
}

.lf-section-sub {
  font-size: 16px;
  color: var(--muted);
  max-width: 560px;
  margin-bottom: 40px;
  line-height: 1.6;
}

.lf-divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--border), transparent);
  margin: 0 24px 80px;
  max-width: var(--max);
  margin-left: auto;
  margin-right: auto;
}


.lf-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}
.lf-grid-2 { grid-template-columns: repeat(2, 1fr); }
.lf-grid-4 { grid-template-columns: repeat(4, 1fr); }

.lf-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  transition: all .2s;
}
.lf-card:hover {
  border-color: #cbd5e1;
  box-shadow: 0 4px 24px rgba(15,23,42,.07);
  transform: translateY(-2px);
}
.lf-card-icon {
  width: 40px;
  height: 40px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  margin-bottom: 16px;
  flex-shrink: 0;
}
.lf-card h3 {
  font-size: 15px;
  font-weight: 700;
  color: var(--ink);
  margin-bottom: 6px;
  line-height: 1.3;
}
.lf-card p {
  font-size: 13px;
  color: var(--muted);
  line-height: 1.6;
}
.lf-card ul {
  list-style: none;
  margin-top: 12px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.lf-card ul li {
  font-size: 12px;
  color: var(--muted);
  display: flex;
  align-items: flex-start;
  gap: 7px;
  line-height: 1.5;
}
.lf-card ul li::before {
  content: '·';
  color: var(--red);
  font-weight: 700;
  flex-shrink: 0;
  margin-top: 1px;
}


.lf-card-featured {
  border-color: var(--red);
  background: linear-gradient(135deg, #fff5f5 0%, #fff 60%);
}
.lf-card-featured:hover { border-color: var(--red); }


.lf-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 24px;
}
.lf-chip {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 7px 14px;
  border-radius: 100px;
  border: 1px solid var(--border);
  background: var(--card);
  font-size: 13px;
  font-weight: 600;
  color: var(--ink);
  box-shadow: 0 1px 4px rgba(15,23,42,.05);
}
.lf-chip-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}
.lf-chip-badge {
  font-size: 10px;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 100px;
  background: #fef3c7;
  color: #92400e;
  margin-left: 2px;
}

.lf-stats {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  margin-bottom: 48px;
}
.lf-stat {
  background: var(--light);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  text-align: center;
}
.lf-stat-num {
  font-size: 32px;
  font-weight: 800;
  background: linear-gradient(135deg, var(--red), var(--blue));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  line-height: 1.2;
}
.lf-stat-label {
  font-size: 12px;
  color: var(--muted);
  font-weight: 500;
  margin-top: 4px;
}

/* ── MCP TOOL TABLE ── */
.lf-tools {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
}
.lf-tool {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 14px 16px;
  background: var(--light);
  border: 1px solid var(--border);
  border-radius: 10px;
}
.lf-tool-icon {
  width: 32px;
  height: 32px;
  border-radius: 8px;
  background: var(--ink);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 700;
  flex-shrink: 0;

}
.lf-tool-name {
  font-size: 13px;
  font-weight: 700;
  color: var(--ink);

  margin-bottom: 3px;
}
.lf-tool-desc {
  font-size: 12px;
  color: var(--muted);
  line-height: 1.5;
}

/* ── SYNCIFIC SECTION ── */
.lf-syncific {
  background: var(--dark);
  padding: 80px 24px;
  margin-top: 80px;
}
.lf-syncific-inner {
  max-width: var(--max);
  margin: 0 auto;
}
.lf-syncific .lf-section-label { color: rgba(255,255,255,.4); }
.lf-syncific .lf-section-label span { background: rgba(255,255,255,.15); }
.lf-syncific .lf-section-title { color: #fff; }
.lf-syncific .lf-section-title em { color: var(--gold); }
.lf-syncific .lf-section-sub { color: rgba(255,255,255,.5); }

.lf-syncific .lf-card {
  background: rgba(255,255,255,.04);
  border-color: rgba(255,255,255,.08);
}
.lf-syncific .lf-card:hover {
  background: rgba(255,255,255,.07);
  border-color: rgba(255,255,255,.15);
  transform: translateY(-2px);
}
.lf-syncific .lf-card h3 { color: #fff; }
.lf-syncific .lf-card p { color: rgba(255,255,255,.5); }
.lf-syncific .lf-card ul li { color: rgba(255,255,255,.45); }
.lf-syncific .lf-card ul li::before { color: var(--gold); }

.lf-syncific .lf-chip {
  background: rgba(255,255,255,.06);
  border-color: rgba(255,255,255,.1);
  color: rgba(255,255,255,.85);
}

.lf-syncific-cta {
  margin-top: 48px;
  padding: 32px;
  border: 1px solid rgba(255,255,255,.1);
  border-radius: var(--radius);
  background: rgba(255,255,255,.03);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  flex-wrap: wrap;
}
.lf-syncific-cta p {
  font-size: 14px;
  color: rgba(255,255,255,.5);
  margin-top: 4px;
}
.lf-syncific-cta h3 { font-size: 18px; font-weight: 700; color: #fff; }
.lf-btn-syncific {
  background: linear-gradient(135deg, var(--red), var(--blue));
  color: #fff;
  border: none;
  white-space: nowrap;
  flex-shrink: 0;
}
.lf-btn-syncific:hover { opacity: .9; transform: translateY(-1px); }

/* ── PATENT BADGE ── */
.lf-patent {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 11px;
  font-weight: 600;
  color: var(--muted);
  padding: 6px 14px;
  border: 1px solid var(--border);
  border-radius: 100px;
  margin-bottom: 40px;
}


/* ── RESPONSIVE ── */
@media (max-width: 900px) {
  .lf-grid { grid-template-columns: repeat(2, 1fr); }
  .lf-grid-4 { grid-template-columns: repeat(2, 1fr); }
  .lf-stats { grid-template-columns: repeat(2, 1fr); }
  .lf-tools { grid-template-columns: 1fr; }
}
@media (max-width: 600px) {
  .lf-grid { grid-template-columns: 1fr; }
  .lf-grid-2 { grid-template-columns: 1fr; }
  .lf-stats { grid-template-columns: repeat(2, 1fr); }
  .lf-syncific-cta { flex-direction: column; }
}

.md-root{
  --ink:#171A1F; --ink-2:#474C56; --ink-3:#6E7480;
  --paper:#F6F7F4; --surface:#FFFFFF; --line:#ff5757; --line-2:#EEEFEA;
  --debt:#ff5757; --debt-ink:#000000; --debt-tint:#F8ECE8;
  --sync:#ffbc59; --sync-ink:#ff5757; --sync-tint:#E7F1EF;
  --accrue:#946410; --accrue-tint:#F6EEDD;

}

/* ---- progress bar ---- */
.md-progress{position:fixed;top:0;left:0;right:0;height:3px;z-index:9999;background:transparent;}
.md-progress__bar{display:block;height:100%;width:0;background:var(--debt);transition:width .08s linear;}

/* ---- eyebrows / kickers (mono ledger thread) ---- */
.md-eyebrow,.md-kicker{
  font-family:var(--mono);font-size:.72rem;font-weight:500;letter-spacing:.13em;
  text-transform:uppercase;color:var(--ink-3);margin:0;
}
.md-kicker{color:var(--debt);margin-bottom:.5rem;}



/* ledger signature */
.md-ledger{margin:2.4rem 0 0;max-width:430px;background:var(--surface);
  border:1px solid var(--line);border-radius:10px;padding:1rem 1.15rem 1.1rem;
  box-shadow:0 1px 0 rgba(0,0,0,.02),0 10px 30px -22px rgba(20,22,28,.5);}
.md-ledger__cap{font-family:var(--mono);font-size:.66rem;letter-spacing:.12em;
  text-transform:uppercase;color:var(--ink-3);margin:0 0 .7rem;padding-bottom:.6rem;
  border-bottom:1px solid var(--line-2);}
.md-ledger__row{display:flex;justify-content:space-between;align-items:center;gap:1rem;}
.md-ledger__label{font-weight:600;font-size:.98rem;}
.md-ledger__tag{font-family:var(--mono);font-size:.68rem;letter-spacing:.08em;
  text-transform:uppercase;color:var(--debt);background:var(--debt-tint);
  border:1px solid #ecd6cf;border-radius:5px;padding:.2rem .5rem;}
.md-ledger__row--detail{margin-top:.55rem;font-size:.82rem;color:var(--ink-3);font-family:var(--mono);}
.md-ledger__fig{color:var(--accrue);}

/* ===================== GRID / TOC ===================== */
.md-grid{max-width:var(--maxw);margin:0 auto;padding:0 clamp(1.2rem,5vw,2.4rem);
  display:grid;grid-template-columns:1fr;gap:0;}
@media(min-width:1024px){
  .md-grid{grid-template-columns:230px minmax(0,1fr);gap:clamp(2.5rem,4vw,4.5rem);align-items:start;}
}
.md-toc{padding-top:2.6rem;}
@media(min-width:1024px){.md-toc{position:sticky;top:1.4rem;padding-top:3.4rem;}}
.md-toc__wrap{border-top:2px solid var(--ink);padding-top:.9rem;}
.md-toc__title{font-family:var(--mono);font-size:.72rem;letter-spacing:.12em;text-transform:uppercase;
  color:var(--ink);cursor:pointer;list-style:none;font-weight:600;}
.md-toc__title::-webkit-details-marker{display:none;}
.md-toc__list{list-style:none;margin:1rem 0 0;padding:0;counter-reset:toc;}
.md-toc__list li{margin:0;counter-increment:toc;}
.md-toc__list a{display:block;font-size:.86rem;line-height:1.3;color:var(--ink-3);
  text-decoration:none;padding:.36rem 0 .36rem 1.9rem;position:relative;
  border-left:2px solid transparent;transition:color .15s,border-color .15s;}
.md-toc__list a::before{content:counter(toc,decimal-leading-zero);font-family:var(--mono);
  font-size:.64rem;position:absolute;left:.55rem;top:.5rem;color:var(--line);}
.md-toc__list a:hover{color:var(--ink);}
.md-toc__list a.is-active{color:var(--debt);border-left-color:var(--debt);}
.md-toc__list a.is-active::before{color:var(--debt);}
@media(max-width:1023px){
  .md-toc__wrap{background:var(--surface);border:1px solid var(--line);border-top:2px solid var(--ink);
    border-radius:8px;padding:1rem 1.1rem;}
  .md-toc__list{columns:2;column-gap:1.4rem;}
  .md-toc__list a{padding-left:1.7rem;}
}

/* ===================== BODY ===================== */

.md-mono{font-family:var(--mono);font-size:.88em;background:var(--line-2);
  padding:.08em .35em;border-radius:4px;color:var(--debt-ink);}

.md-section{margin-top:3rem;scroll-margin-top:1.5rem;}
.md-section h2{font-family:var(--serif);font-weight:500;letter-spacing:-.01em;
  font-size:clamp(1.7rem,3.6vw,2.35rem);line-height:1.12;margin:.2rem 0 1rem;color:var(--ink);}
.md-section--conclusion h2{color:var(--debt-ink);}

/* definition / callout */
.md-callout{margin:2rem 0;padding:1.3rem 1.5rem;border-radius:10px;background:var(--surface);
  border:1px solid var(--line);position:relative;}
.md-callout--def{background:var(--debt-tint);border-color:#eed8d1;}
.md-callout__k{font-family:var(--mono);font-size:.7rem;letter-spacing:.12em;text-transform:uppercase;
  color:var(--debt);margin:0 0 .5rem;}
.md-callout__body{margin:0;font-size:1.06rem;line-height:1.55;color:var(--debt-ink);}
.md-callout__body strong{color:var(--debt);}

/* pull quotes — break out wider than column */
.md-pull{margin:2.6rem 0;padding:0;}
.md-pull blockquote{margin:0;font-family:var(--serif);font-style:italic;font-weight:400;
  font-size:clamp(1.5rem,3.4vw,2.05rem);line-height:1.3;letter-spacing:-.01em;color:var(--ink);
  padding-left:1.4rem;border-left:3px solid var(--debt);}
.md-pull--close blockquote{border-left-color:var(--sync);color:var(--sync-ink);}
@media(min-width:1024px){.md-pull{margin-left:-2.5rem;margin-right:-2.5rem;}}

/* cost cards */
.md-cards{display:grid;grid-template-columns:repeat(2,1fr);gap:1px;background:var(--line);
  border:1px solid var(--line);border-radius:10px;overflow:hidden;margin:1.8rem 0;}
@media(min-width:560px){.md-cards{grid-template-columns:repeat(4,1fr);}}
.md-card{background:var(--surface);padding:1.1rem 1.15rem;}
.md-card__n{display:block;font-family:var(--mono);font-size:.72rem;letter-spacing:.1em;
  text-transform:uppercase;color:var(--debt);margin-bottom:.5rem;}
.md-card p{margin:0;font-size:.9rem;line-height:1.45;color:var(--ink-2);}

/* figure shell */
.md-fig{margin:2.2rem 0;}
.md-fig__cap{font-family:var(--mono);font-size:.7rem;letter-spacing:.1em;text-transform:uppercase;
  color:var(--ink-3);margin-bottom:.9rem;}

/* fan-out: one becomes fifty */
.md-fan{display:grid;grid-template-columns:auto 1fr;gap:0 1.2rem;align-items:center;
  background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:1.5rem;}
.md-fan__source{display:flex;align-items:center;justify-content:center;text-align:center;
  width:96px;height:96px;border-radius:12px;background:var(--sync-tint);border:1.5px solid var(--sync);
  color:var(--sync-ink);font-weight:600;font-size:.82rem;line-height:1.2;flex:none;}
.md-fan__arrows{display:none;}
.md-fan__targets{display:flex;flex-wrap:wrap;gap:.5rem;}
.md-chip{font-family:var(--mono);font-size:.74rem;background:var(--debt-tint);color:var(--debt-ink);
  border:1px solid #ecd6cf;border-radius:6px;padding:.32rem .6rem;}
.md-chip--ghost{background:repeating-linear-gradient(45deg,var(--debt-tint),var(--debt-tint) 5px,#fff 5px,#fff 10px);
  color:var(--debt);border-style:dashed;}
@media(max-width:560px){.md-fan{grid-template-columns:1fr;gap:1.1rem;}.md-fan__source{margin:0 auto;}}

/* flows: traditional vs connected */
.md-flows{display:grid;grid-template-columns:1fr;gap:1rem;}
@media(min-width:560px){.md-flows{grid-template-columns:1fr 1fr;}}
.md-flow{background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:1.3rem 1.3rem 1.5rem;}
.md-flow__title{font-family:var(--mono);font-size:.74rem;letter-spacing:.1em;text-transform:uppercase;
  margin:0 0 1rem;font-weight:600;}
.md-flow--debt{border-top:3px solid var(--debt);}
.md-flow--debt .md-flow__title{color:var(--debt);}
.md-flow--sync{border-top:3px solid var(--sync);}
.md-flow--sync .md-flow__title{color:var(--sync-ink);}
.md-flow__steps{list-style:none;margin:0;padding:0;counter-reset:step;}
.md-flow__steps li{position:relative;padding:.5rem 0 .5rem 0;font-weight:500;font-size:.96rem;}
.md-flow__steps li:not(:last-child)::after{content:"↓";display:block;color:var(--ink-3);
  font-size:.85rem;margin-top:.35rem;opacity:.6;}
.md-flow__loop{color:var(--debt);font-family:var(--mono);font-size:.84rem;font-weight:500;}
.md-flow--debt .md-flow__steps li:last-child::after{content:"↺";color:var(--debt);opacity:1;display:inline;margin-left:.4rem;}
.md-flow__done{color:var(--sync-ink);font-family:var(--mono);font-size:.84rem;font-weight:500;}

/* compounding */
.md-compound{display:grid;grid-template-columns:repeat(4,1fr);gap:.7rem;align-items:end;
  background:var(--surface);border:1px solid var(--line);border-radius:12px;
  padding:1.5rem 1.3rem 1.2rem;min-height:230px;}
.md-comp{display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:170px;text-align:center;}
.md-comp__bar{width:100%;max-width:52px;height:var(--h);border-radius:6px 6px 0 0;
  background:linear-gradient(var(--accrue),var(--debt));margin-bottom:.7rem;
  transition:height .9s cubic-bezier(.2,.7,.2,1);}
.md-comp--max .md-comp__bar{background:linear-gradient(var(--debt),var(--debt-ink));}
.md-comp__n{font-family:var(--mono);font-size:.76rem;font-weight:600;color:var(--ink);}
.md-comp__v{font-size:.72rem;color:var(--ink-3);line-height:1.25;margin-top:.2rem;}

/* checklist */
.md-check{list-style:none;margin:1.8rem 0;padding:0;display:grid;gap:.7rem;}
.md-check li{display:grid;grid-template-columns:auto 1fr;gap:.85rem;align-items:start;
  background:var(--surface);border:1px solid var(--line);border-radius:10px;padding:1rem 1.15rem;
  font-size:.96rem;line-height:1.5;color:var(--ink-2);cursor:pointer;transition:border-color .15s,background .15s;}
.md-check li strong{color:var(--ink);font-weight:600;}
.md-check li:hover{border-color:var(--sync);}
.md-check__box{width:22px;height:22px;border-radius:6px;border:2px solid var(--sync);
  flex:none;margin-top:.1rem;position:relative;transition:background .15s;}
.md-check li.is-done .md-check__box{background:var(--sync);}
.md-check li.is-done .md-check__box::after{content:"✓";color:#fff;font-size:.8rem;font-weight:700;
  position:absolute;inset:0;display:flex;align-items:center;justify-content:center;}
.md-check li.is-done{opacity:.62;}

.md-soft-note{font-size:1.02rem;color:var(--ink-2);border-top:1px solid var(--line);padding-top:1.3rem;margin-top:1.6rem;}

/* ===================== FAQ ===================== */
.md-faq{margin-top:3.4rem;}
.md-q{border-bottom:1px solid var(--line);}
.md-q:first-of-type{border-top:1px solid var(--line);}
.md-q summary{list-style:none;cursor:pointer;font-family:var(--serif);font-weight:500;
  font-size:1.14rem;color:var(--ink);padding:1.1rem 2.2rem 1.1rem 0;position:relative;}
.md-q summary::-webkit-details-marker{display:none;}
.md-q summary::after{content:"+";position:absolute;right:.2rem;top:50%;transform:translateY(-50%);
  font-family:var(--mono);font-size:1.3rem;color:var(--debt);transition:transform .2s;}
.md-q[open] summary::after{content:"–";}
.md-q__a{padding:0 0 1.15rem;}
.md-q__a p{margin:0;color:var(--ink-2);font-size:.98rem;}

/* ===================== CTA ===================== */
.md-cta{margin-top:4rem;background:var(--ink);color:#fff;}
.md-cta__inner{max-width:var(--maxw);margin:0 auto;padding:clamp(3rem,6vw,4.6rem) clamp(1.2rem,5vw,2.4rem);
  max-width:760px;text-align:center;}
.md-cta__eyebrow{font-family:var(--mono);font-size:.72rem;letter-spacing:.14em;text-transform:uppercase;
  color:#9aa4ae;margin:0 0 1rem;}
.md-cta__title{font-family:var(--serif);font-weight:500;font-size:clamp(1.9rem,4.5vw,2.9rem);
  line-height:1.1;letter-spacing:-.015em;margin:0 0 1.1rem;color:#fff;}
.md-cta__body{color:#c8ced5;font-size:1.08rem;line-height:1.6;margin:0 auto 2rem;max-width:54ch;}
.md-cta__actions{display:flex;gap:.8rem;justify-content:center;flex-wrap:wrap;}
.md-btn{display:inline-block;font-family:var(--sans);font-weight:600;font-size:.95rem;
  text-decoration:none;padding:.85rem 1.5rem;border-radius:30px;transition:transform .12s,background .15s,box-shadow .15s;}
.md-btn--primary{background:var(--sync);color:#fff;box-shadow:0 6px 20px -8px rgba(14,110,100,.8);}
.md-btn--primary:hover{background:#000;transform:translateY(-1px); color:#ffffff}
.md-btn--ghost{background:transparent;color:#fff;border:1px solid #3a4048;}
.md-btn--ghost:hover{border-color:#5a626c;background:rgba(255,255,255,.04); color:#ffbc59}

/* focus + motion */
.md-root a:focus-visible,.md-root summary:focus-visible,.md-check li:focus-visible{
  outline:2px solid var(--sync);outline-offset:3px;border-radius:4px;}
@media(prefers-reduced-motion:reduce){
  .md-root *{transition:none!important;animation:none!important;scroll-behavior:auto!important;}
}
.md-root{scroll-behavior:smooth;}
</style>
