}

/* Optional divider */
.lsp-login-divider {
  display: flex;
  align-items: center;
  margin: 24px 0 16px;
  font-size: 12px;
  color: #9ca3af;
}

.lsp-login-divider::before,
.lsp-login-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: #e5e7eb;
}

.lsp-login-divider span {
  padding: 0 12px;
}</style>
